import {
    BrowserRouter,
    Routes,
    Route
}

from "react-router-dom";

import Home from "./pages/Home";

import BookingPage from "./pages/BookingPage";

import RegisterPage from "./pages/RegisterPage";

function App() {

    return (

        <BrowserRouter>

            <Routes>

                <Route
                    path="/"
                    element={<Home />}
                />

                <Route
                    path="/booking/:id"
                    element={<BookingPage />}
                />

                <Route
                    path="/register"
                    element={<RegisterPage />}
                />

            </Routes>

        </BrowserRouter>
    );
}

export default App;
